import React, { useState, useEffect } from 'react';
import WelcomeOnboarding from './components/WelcomeOnboarding';
import LoginComponent from './components/LoginComponent';
import VerificationPage from './components/VerificationPage';
import DashboardScreen from './components/DashboardScreen';
import RecipeDetailScreen from './components/RecipeDetailScreen';
import RecipeDetailScreenMobile from './components/RecipeDetailScreenMobile';
import RecipeGeneratorScreen from './components/RecipeGeneratorScreen';
import WeeklyRecipesScreen from './components/WeeklyRecipesScreen';
import StarbucksGeneratorScreen from './components/StarbucksGeneratorScreen';
import RecipeHistoryScreen from './components/RecipeHistoryScreen';
import TutorialScreen from './components/TutorialScreen';
import TrialWelcomeScreen from './components/TrialWelcomeScreen';
import SettingsScreen from './components/SettingsScreen';
import SubscriptionSuccessScreen from './components/SubscriptionSuccessScreen';
import LegalDocumentLink from './components/LegalDocumentLink';
import LegalDocumentModal from './components/LegalDocumentModal';
import { authService } from './services/auth';
import './App.css';

const VIEW_TO_PATH = {
  welcome: '/signup',
  login: '/login',
  verification: '/verify',
  dashboard: '/dashboard',
  'trial-welcome': '/trial-welcome',
  'recipe-generator': '/recipe-generator',
  'weekly-recipes': '/weekly-recipes',
  tutorial: '/tutorial',
  'starbucks-generator': '/starbucks-generator',
  'starbucks-detail': '/starbucks-detail',
  'recipe-history': '/recipe-history',
  'recipe-detail': '/recipe-detail',
  settings: '/settings',
  'subscription-success': '/subscription-success',
  'shopping-list': '/shopping-list',
};

const PATH_ALIASES = {
  '/': 'login',
  '/landing': 'login',
  '/welcome': 'welcome',
  '/signup': 'welcome',
  '/register': 'welcome',
  '/login': 'login',
  '/verify': 'verification',
  '/verification': 'verification',
  '/dashboard': 'dashboard',
  '/trial-welcome': 'trial-welcome',
  '/recipe-generator': 'recipe-generator',
  '/generate-recipe': 'recipe-generator',
  '/weekly-recipes': 'weekly-recipes',
  '/weekly-planner': 'weekly-recipes',
  '/tutorial': 'tutorial',
  '/how-to-use': 'tutorial',
  '/starbucks-generator': 'starbucks-generator',
  '/starbucks-detail': 'starbucks-detail',
  '/starbucks': 'starbucks-generator',
  '/recipe-history': 'recipe-history',
  '/history': 'recipe-history',
  '/recipe-detail': 'recipe-detail',
  '/settings': 'settings',
  '/subscription-success': 'subscription-success',
  '/shopping-list': 'shopping-list',
};

const getViewFromPath = (pathname) => PATH_ALIASES[pathname] || 'login';
const FOOTER_VIEWS = new Set([
  'dashboard',
  'trial-welcome',
  'recipe-generator',
  'weekly-recipes',
  'tutorial',
  'starbucks-generator',
  'starbucks-detail',
  'recipe-history',
  'recipe-detail',
  'settings',
  'shopping-list',
]);

function App() {
  const [currentView, setCurrentView] = useState(() => getViewFromPath(window.location.pathname));
  const [user, setUser] = useState(null);
  const [selectedRecipe, setSelectedRecipe] = useState(null);
  const [notification, setNotification] = useState(null);
  const [verificationEmail, setVerificationEmail] = useState('');
  const [pendingVerificationLogin, setPendingVerificationLogin] = useState(null);
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);
  const [activeLegalDocument, setActiveLegalDocument] = useState(null);

  // Check for existing user session on app load
  useEffect(() => {
    const savedUser = localStorage.getItem('user') || sessionStorage.getItem('user');
    if (savedUser) {
      try {
        const userData = JSON.parse(savedUser);
        setUser(userData);
        const pathView = getViewFromPath(window.location.pathname);
        // Preserve explicit deep links like subscription return pages.
        if (['login', 'welcome'].includes(pathView)) {
          setCurrentView('dashboard');
        }
      } catch (error) {
        console.error('Error parsing saved user data:', error);
        localStorage.removeItem('user');
      }
    }
  }, []); // Keep empty dependency array

  // Handle responsive design changes
  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth <= 768);
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Expose setCurrentView globally for dashboard navigation
  useEffect(() => {
    window.setCurrentScreen = setCurrentView;
    window.setSelectedRecipe = setSelectedRecipe;
  }, []); // Keep this cleanup as it's for globals

  // Sync browser navigation (back/forward) with the app's internal screen state.
  useEffect(() => {
    const handlePopState = () => {
      setCurrentView(getViewFromPath(window.location.pathname));
    };

    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  // Keep the URL in sync when the app changes views programmatically.
  useEffect(() => {
    const targetPath = VIEW_TO_PATH[currentView];
    if (!targetPath) return;
    if (window.location.pathname === targetPath) return;
    window.history.pushState({}, '', targetPath);
  }, [currentView]);

  const showNotification = (message, type = 'info') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 5000);
  };

  const normalizeUserData = (userData) => ({
      user_id: userData.user_id,
      id: userData.user_id, // Add both fields for compatibility
      email: userData.email,
      name: userData.name || [userData.first_name, userData.last_name].filter(Boolean).join(' '),
      verified: userData.verified ?? userData.is_verified,
      subscription_status: userData.subscription_status
    });

  const persistAuthenticatedUser = (normalizedUser, rememberMe = true) => {
    setUser(normalizedUser);
    if (rememberMe) {
      localStorage.setItem('user', JSON.stringify(normalizedUser));
      localStorage.setItem('rememberMe', 'true');
      sessionStorage.removeItem('user');
      return;
    }

    sessionStorage.setItem('user', JSON.stringify(normalizedUser));
    localStorage.removeItem('user');
    localStorage.removeItem('rememberMe');
  };

  const handleLoginSuccess = (userData, options = {}) => {
    const { nextView = 'dashboard', successMessage } = options;

    const normalizedUser = normalizeUserData(userData);
    const rememberMe = userData.rememberMe !== false;

    persistAuthenticatedUser(normalizedUser, rememberMe);
    setCurrentView(nextView);
    showNotification(successMessage || `Welcome back, ${userData.name || userData.email}!`, 'success');
  };

  const handleVerificationRequired = (data) => {
    setVerificationEmail(data.email);
    setPendingVerificationLogin(null);
    setCurrentView('verification');
    showNotification('Please check your email for verification code.', 'info');
  };

  const handleRegistrationVerificationRequired = (data, credentials) => {
    setVerificationEmail(data.email);
    setPendingVerificationLogin(credentials || null);
    setCurrentView('verification');
    showNotification('Account created. Enter the code sent to your email to continue.', 'info');
  };

  const handleVerificationSuccess = async (data) => {

    if (
      pendingVerificationLogin?.email &&
      pendingVerificationLogin?.password &&
      pendingVerificationLogin.email.toLowerCase() === (data.email || '').toLowerCase()
    ) {
      try {
        const loginResult = await authService.login({
          email: pendingVerificationLogin.email,
          password: pendingVerificationLogin.password
        });

        setPendingVerificationLogin(null);
        setVerificationEmail('');
        handleLoginSuccess({
          ...loginResult,
          verified: loginResult.is_verified,
          name: [loginResult.first_name, loginResult.last_name].filter(Boolean).join(' ')
        }, {
          nextView: 'trial-welcome',
          successMessage: 'Email verified. Your free trial is ready.'
        });
        return;
      } catch (error) {
        console.error('❌ Auto-login after verification failed:', error);
        showNotification('Email verified. Please log in to continue.', 'warning');
      }
    } else {
      showNotification('Email verified! You can now log in.', 'success');
    }

    setPendingVerificationLogin(null);
    setCurrentView('login');
    setVerificationEmail('');
  };

  const handleRegistrationComplete = (userData) => {
    const normalizedUser = {
      user_id: userData.user_id,
      id: userData.user_id, // Add both fields for compatibility
      email: userData.email,
      name: userData.name || [userData.first_name, userData.last_name].filter(Boolean).join(' '),
      verified: userData.verified || false,
      subscription_status: userData.subscription_status || 'free'
    };

    persistAuthenticatedUser(normalizedUser, true);
    setCurrentView('trial-welcome');
    showNotification('Welcome! Your free trial is active.', 'success');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('user');
    sessionStorage.removeItem('user');
    localStorage.removeItem('userPreferences');
    localStorage.removeItem('rememberMe');
    setCurrentView('login');
    showNotification('You have been logged out.', 'info');
  };

  const handleRecipeSelect = (recipe) => {
    setSelectedRecipe(recipe);
    setCurrentView('recipe-detail');
  };

  const handleBackFromRecipe = () => {
    setSelectedRecipe(null);
    setCurrentView('dashboard');
  };

  const getStoredUserForRecovery = () => {
    const rawLocal = localStorage.getItem('user');
    const rawSession = sessionStorage.getItem('user');
    const storageType = rawLocal ? 'local' : (rawSession ? 'session' : null);
    const raw = rawLocal || rawSession;
    if (!raw) return { user: null, storageType: null };

    try {
      return { user: JSON.parse(raw), storageType };
    } catch (e) {
      return { user: null, storageType: null };
    }
  };

  const renderCurrentView = () => {
    switch (currentView) {
      case 'welcome':
        return (
          <WelcomeOnboarding
            onComplete={handleRegistrationComplete}
            onSkip={() => setCurrentView('login')}
            showLoginOption={true}
            onLoginClick={() => setCurrentView('login')}
            onRegistrationVerificationRequired={handleRegistrationVerificationRequired}
            onOpenLegalDocument={setActiveLegalDocument}
          />
        );

      case 'login':
        return (
          <div className="min-h-screen bg-gradient-to-br from-blue-50 via-purple-50 to-pink-50 flex items-center justify-center p-4">
            <div className="max-w-md w-full">
              {/* Login Card */}
              <div className="bg-white rounded-2xl shadow-xl p-8 border border-gray-100">
                <div className="text-center mb-6">
                  <h1 className="text-2xl font-bold text-gray-800 mb-2">Welcome Back!</h1>
                  <p className="text-gray-600">Sign in to your account</p>
                </div>

                <LoginComponent
                  onLoginSuccess={handleLoginSuccess}
                  onVerificationRequired={handleVerificationRequired}
                  onOpenLegalDocument={setActiveLegalDocument}
                />

                {/* Register Option */}
                <div className="mt-6 text-center">
                  <p className="text-gray-600">
                    Don't have an account?{' '}
                    <button
                      onClick={() => setCurrentView('welcome')}
                      className="text-blue-600 hover:text-blue-800 font-medium"
                    >
                      Create one here
                    </button>
                  </p>
                </div>
              </div>
            </div>
          </div>
        );

      case 'verification':
        return (
          <VerificationPage
            email={verificationEmail}
            onVerificationSuccess={handleVerificationSuccess}
            onBackToLogin={() => setCurrentView('login')}
          />
        );

      case 'dashboard':
        return (
          <DashboardScreen
            user={user}
            onLogout={handleLogout}
            onRecipeSelect={handleRecipeSelect}
            showNotification={showNotification}
            setCurrentScreen={setCurrentView}
          />
        );

      case 'trial-welcome':
        return (
          <TrialWelcomeScreen
            user={user}
            onContinue={() => setCurrentView(user ? 'dashboard' : 'login')}
            showNotification={showNotification}
          />
        );

      case 'recipe-generator':
        return (
          <RecipeGeneratorScreen
            user={user}
            onBack={() => setCurrentView('dashboard')}
            showNotification={showNotification}
            onViewRecipe={(recipeId, source, options) => {
              setSelectedRecipe({ id: recipeId, source, triggerWalmartFetch: options?.triggerWalmartFetch });
              setCurrentView('recipe-detail');
            }}
          />
        );

      case 'weekly-recipes':
        return (
          <WeeklyRecipesScreen
            user={user}
            onBack={() => setCurrentView('dashboard')}
            showNotification={showNotification}
            onViewRecipe={(recipeId, source) => {
              setSelectedRecipe({ id: recipeId, source });
              setCurrentView('recipe-detail');
            }}
          />
        );

      case 'tutorial':
        return (
          <TutorialScreen
            setCurrentScreen={setCurrentView}
            showNotification={showNotification}
          />
        );

      case 'starbucks-generator':
        return (
          <StarbucksGeneratorScreen
            user={user}
            setCurrentScreen={setCurrentView}
            showNotification={showNotification}
          />
        );

      case 'recipe-history':
        return (
          <RecipeHistoryScreen
            user={user}
            onBack={() => setCurrentView('dashboard')}
            showNotification={showNotification}
            onViewRecipe={(recipeId, source) => {
              setSelectedRecipe({ id: recipeId, source });
              setCurrentView('recipe-detail');
            }}
            onViewStarbucksRecipe={(recipe) => {
              setSelectedRecipe({ ...recipe, source: 'history' });
              setCurrentView('starbucks-detail');
            }}
          />
        );

      case 'starbucks-detail':
        return selectedRecipe ? (
          <StarbucksGeneratorScreen
            user={user}
            setCurrentScreen={setCurrentView}
            showNotification={showNotification}
            initialDrink={selectedRecipe}
            backDestination="recipe-history"
          />
        ) : (
          <div className="min-h-screen bg-gradient-to-br from-red-50 to-orange-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-2xl shadow-xl p-8 max-w-md w-full text-center">
              <div className="text-4xl mb-4">❌</div>
              <h2 className="text-2xl font-bold text-gray-800 mb-4">Drink Not Found</h2>
              <p className="text-gray-600 mb-6">The Starbucks drink you're looking for could not be loaded.</p>
              <button
                onClick={() => setCurrentView('recipe-history')}
                className="bg-blue-500 text-white px-6 py-3 rounded-lg hover:bg-blue-600 transition-colors"
              >
                ← Back to Recipe History
              </button>
            </div>
          </div>
        );

      case 'recipe-detail':
        return selectedRecipe ? (
          isMobile ? (
            <RecipeDetailScreenMobile
              recipeId={selectedRecipe.id}
              recipeSource={selectedRecipe.source || "generated"}
              triggerWalmartFetch={selectedRecipe.triggerWalmartFetch}
              onBack={() => {
                // FIX: Better back navigation based on source
                if (selectedRecipe.source === 'generated') {
                  setCurrentView('recipe-generator');
                } else if (selectedRecipe.source === 'history') {
                  setCurrentView('recipe-history');
                } else if (selectedRecipe.source === 'weekly') {
                  setCurrentView('weekly-recipes');
                } else {
                  setCurrentView('dashboard');
                }
              }}
              showNotification={showNotification}
            />
          ) : (
            <RecipeDetailScreen
              recipeId={selectedRecipe.id}
              recipeSource={selectedRecipe.source || "generated"}
              triggerWalmartFetch={selectedRecipe.triggerWalmartFetch}
              onBack={() => {
                // FIX: Better back navigation based on source
                if (selectedRecipe.source === 'generated') {
                  setCurrentView('recipe-generator');
                } else if (selectedRecipe.source === 'history') {
                  setCurrentView('recipe-history');
                } else if (selectedRecipe.source === 'weekly') {
                  setCurrentView('weekly-recipes');
                } else {
                  setCurrentView('dashboard');
                }
              }}
              showNotification={showNotification}
            />
          )
        ) : (
          <div className="min-h-screen bg-gradient-to-br from-red-50 to-orange-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-2xl shadow-xl p-8 max-w-md w-full text-center">
              <div className="text-4xl mb-4">❌</div>
              <h2 className="text-2xl font-bold text-gray-800 mb-4">Recipe Not Found</h2>
              <p className="text-gray-600 mb-6">The recipe you're looking for could not be loaded.</p>
              <button
                onClick={() => setCurrentView('dashboard')}
                className="bg-blue-500 text-white px-6 py-3 rounded-lg hover:bg-blue-600 transition-colors"
              >
                ← Back to Dashboard
              </button>
            </div>
          </div>
        );

      case 'settings':
        return (
          <SettingsScreen
            user={user}
            onBack={() => setCurrentView(user ? 'dashboard' : 'login')}
            onLogout={handleLogout}
            showNotification={showNotification}
            onOpenLegalDocument={setActiveLegalDocument}
          />
        );

      case 'subscription-success':
        return (
          <SubscriptionSuccessScreen
            showNotification={showNotification}
            onClose={() => {
              const recovered = getStoredUserForRecovery();
              const activeUser = user || recovered.user;

              if (activeUser) {
                const updatedUser = { ...activeUser, subscription_status: 'active' };
                setUser(updatedUser);

                if (recovered.storageType === 'session') {
                  sessionStorage.setItem('user', JSON.stringify(updatedUser));
                } else {
                  localStorage.setItem('user', JSON.stringify(updatedUser));
                }

                setCurrentView('dashboard');
                return;
              }

              setCurrentView('login');
            }}
          />
        );

      case 'shopping-list':
        return (
          <div className="min-h-screen bg-gradient-to-br from-green-50 to-blue-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-2xl shadow-xl p-8 max-w-md w-full text-center">
              <div className="text-4xl mb-4">🛒</div>
              <h2 className="text-2xl font-bold text-gray-800 mb-4">Shopping List</h2>
              <p className="text-gray-600 mb-6">Smart shopping list features coming soon!</p>
              <button
                onClick={() => setCurrentView('dashboard')}
                className="bg-green-500 text-white px-6 py-3 rounded-lg hover:bg-green-600 transition-colors"
              >
                ← Back to Dashboard
              </button>
            </div>
          </div>
        );

      default:
        return (
          <div className="min-h-screen flex items-center justify-center">
            <div className="text-center">
              <h2 className="text-2xl font-bold text-gray-800 mb-4">Page Not Found</h2>
              <button
                onClick={() => setCurrentView('welcome')}
                className="bg-blue-500 text-white px-6 py-3 rounded-lg hover:bg-blue-600"
              >
                Go to Welcome
              </button>
            </div>
          </div>
        );
    }
  };

  const shouldShowGlobalLegalFooter = FOOTER_VIEWS.has(currentView);

  return (
    <div className="App">
      {/* Global Notification */}
      {notification && (
        <div className={`fixed top-4 right-4 z-50 p-4 rounded-lg shadow-lg max-w-sm ${
          notification.type === 'success' ? 'bg-green-500 text-white' :
          notification.type === 'error' ? 'bg-red-500 text-white' :
          notification.type === 'warning' ? 'bg-yellow-500 text-white' :
          'bg-blue-500 text-white'
        }`}>
          <div className="flex items-center justify-between">
            <span>{notification.message}</span>
            <button
              onClick={() => setNotification(null)}
              className="ml-4 text-white hover:text-gray-200"
            >
              ✕
            </button>
          </div>
        </div>
      )}

      {/* Main Content */}
      {renderCurrentView()}

      {shouldShowGlobalLegalFooter ? (
        <footer className="border-t border-gray-200 bg-white/95 backdrop-blur-sm">
          <div className="max-w-7xl mx-auto px-4 py-3 text-center text-xs sm:text-sm text-gray-600">
            <LegalDocumentLink
              document="privacy"
              onOpen={setActiveLegalDocument}
              className="text-blue-600 hover:text-blue-800 underline"
            />
            {' · '}
            <LegalDocumentLink
              document="terms"
              onOpen={setActiveLegalDocument}
              className="text-blue-600 hover:text-blue-800 underline"
            />
            {' · '}
            <LegalDocumentLink
              document="security"
              onOpen={setActiveLegalDocument}
              className="text-blue-600 hover:text-blue-800 underline"
            />
          </div>
        </footer>
      ) : null}

      <LegalDocumentModal
        documentId={activeLegalDocument}
        onClose={() => setActiveLegalDocument(null)}
      />
    </div>
  );
}

export default App;
